const xml = $json.data || '';

if (!xml || xml.length < 200) {
  throw new Error(`RSS feed unreachable or empty — ${xml.length} chars received`);
}

if (!xml.includes('<rss') && !xml.includes('<feed')) {
  throw new Error(`Response is not a valid RSS/Atom feed — source may have changed`);
}

return $input.all();

const items = $input.first().json.rss.channel.item || [];
const currentYear = new Date().getFullYear();

return items
  .map(i => ({
    json: {
      source: "OCC",
      title: (i.title || "").trim(),
      url: (i.link || "").trim(),
      date: i.pubDate || "",
      date_iso: (() => {
        const d = new Date(i.pubDate);
        return isNaN(d.getTime()) ? "" : d.toISOString().slice(0, 10);
      })(),
      description: (i.description || "").trim()
    }
  }))
  .filter(item => {
    if (!item.json.url || !item.json.title) return false;
    const itemYear = new Date(item.json.date).getFullYear();
    return itemYear === currentYear;
  });

const items = $input.all();
