const url = $json.url || '';
const isPdf = url.toLowerCase().endsWith('.pdf');

let articleText = '';

if (isPdf) {
  // Fetch PDF binary and parse text
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    encoding: 'arraybuffer',
    returnFullResponse: false,
    headers: {
      'User-Agent': 'Mozilla/5.0'
    }
  });

  const buffer = Buffer.from(response);
  const pdfParse = require('pdf-parse');
  const parsed = await pdfParse(buffer);

  articleText = (parsed.text || '')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/ *\n */g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

} else {
  // Parse full HTML fetched by OCC - Fetch Article
  const html = $json.data || '';

  function stripTags(s) {
    return s
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
      .replace(/<img[^>]*>/gi, ' ')
      .replace(/<\/(p|div|section|article|main|br|li|h1|h2|h3|h4|h5|h6)>/gi, '\n')
      .replace(/<[^>]+>/g, ' ');
  }

  function decodeHtml(str) {
    if (!str) return str;
    return str
      .replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
      .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
      .replace(/&#8217;/g, "'").replace(/&#8220;/g, '"').replace(/&#8221;/g, '"')
      .replace(/&#8211;/g, '-').replace(/&#8212;/g, '-').replace(/&apos;/g, "'");
  }

  const mainMatch = html.match(/<main[\s\S]*?<\/main>/i);
  const mainHtml = mainMatch ? mainMatch[0] : html;

  articleText = decodeHtml(stripTags(mainHtml))
    .replace(/Share this/gi, ' ').replace(/Contact the OCC/gi, ' ')
    .replace(/STAY INFORMED/gi, ' ').replace(/HOW CAN WE HELP YOU\?/gi, ' ')
    .replace(/Footer Legal Links[\s\S]*$/i, ' ').replace(/Last Updated:.*$/gim, ' ')
    .replace(/\[[^\]]+\]/g, ' ').replace(/[\w.-]+@[\w.-]+\.\w+/g, ' ')
    .replace(/\u00A0/g, ' ').replace(/\r/g, '\n').replace(/[ \t]+/g, ' ')
    .replace(/ *\n */g, '\n').replace(/\n{2,}/g, '\n\n').trim();
}

return {
  json: {
    source: $json.source || '',
    title: $json.title || '',
    url: $json.url || '',
    date: $json.date || '',
    date_iso: $json.date_iso || '',
    article_clean: articleText
  }
};

const output = $json.output || '';

const cleaned = output
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim()
  .replace(/,(\s*[}\]])/g, '$1');

const parsed = JSON.parse(cleaned);

return {
  ...$json,
  category: parsed.category,
  summary: parsed.summary
};
